"""
Trade Plan Generator for WORED
Generates advisory trade plans based on multiple analytical sources
"""

import argparse
import json
import sys
from typing import Dict, List, Optional, Tuple, Any
from pathlib import Path
import importlib.util


def load_module_from_file(filepath: str, module_name: str):
    """Load a module from a file path"""
    spec = importlib.util.spec_from_file_location(module_name, filepath)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def get_market_context(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Get market context data"""
    try:
        script_path = Path(__file__).parent / "market_context.py"
        if script_path.exists():
            market_context = load_module_from_file(script_path, "market_context")
            # Run the main function with our parameters
            import io
            import contextlib

            # Capture output
            f = io.StringIO()
            with contextlib.redirect_stdout(f):
                # Try to call the main function, assuming it accepts symbol and period
                if hasattr(market_context, 'main'):
                    market_context.main([symbol, period])
                elif hasattr(market_context, '__main__'):
                    # If there's no main function, try to extract data differently
                    pass

            output = f.getvalue()
            # Try to parse as JSON if possible, otherwise return as text
            try:
                return json.loads(output)
            except json.JSONDecodeError:
                # Parse the text output to extract key metrics
                context = {}
                for line in output.split('\n'):
                    if ':' in line:
                        parts = line.split(':', 1)
                        if len(parts) == 2:
                            key = parts[0].strip().lower().replace(' ', '_')
                            value = parts[1].strip()
                            # Try to convert to appropriate type
                            if value.replace('.', '').replace('-', '').isdigit():
                                context[key] = float(value) if '.' in value else int(value)
                            else:
                                context[key] = value
                return context
        else:
            return None
    except Exception as e:
        print(f"Error loading market_context: {e}", file=sys.stderr)
        return None


def get_signal_explainer(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Get signal explainer data"""
    try:
        script_path = Path(__file__).parent / "signal_explainer.py"
        if script_path.exists():
            signal_explainer = load_module_from_file(script_path, "signal_explainer")
            # Similar approach as above to capture output
            import io
            import contextlib

            f = io.StringIO()
            with contextlib.redirect_stdout(f):
                if hasattr(signal_explainer, 'main'):
                    try:
                        signal_explainer.main([symbol, period])
                    except TypeError:
                        # If main doesn't accept arguments, try calling without them
                        signal_explainer.main()

            output = f.getvalue()
            try:
                return json.loads(output)
            except json.JSONDecodeError:
                # Parse text output
                signals = {"signals": []}
                for line in output.split('\n'):
                    if 'signal' in line.lower():
                        signals["signals"].append(line.strip())
                return signals
        else:
            return None
    except Exception as e:
        print(f"Error loading signal_explainer: {e}", file=sys.stderr)
        return None


def get_pattern_lab(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Get pattern lab data"""
    try:
        script_path = Path(__file__).parent / "pattern_lab.py"
        if script_path.exists():
            pattern_lab = load_module_from_file(script_path, "pattern_lab")
            import io
            import contextlib

            f = io.StringIO()
            with contextlib.redirect_stdout(f):
                if hasattr(pattern_lab, 'main'):
                    try:
                        pattern_lab.main([symbol, period])
                    except TypeError:
                        pattern_lab.main()

            output = f.getvalue()
            try:
                return json.loads(output)
            except json.JSONDecodeError:
                # Parse text output
                patterns = {"patterns": []}
                for line in output.split('\n'):
                    if line.strip():
                        patterns["patterns"].append(line.strip())
                return patterns
        else:
            return None
    except Exception as e:
        print(f"Error loading pattern_lab: {e}", file=sys.stderr)
        return None


def get_risk_position(symbol: str, period: str, balance: float, risk_pct: float) -> Optional[Dict]:
    """Get risk position data"""
    try:
        script_path = Path(__file__).parent / "risk_position.py"
        if script_path.exists():
            risk_position = load_module_from_file(script_path, "risk_position")
            import io
            import contextlib

            f = io.StringIO()
            with contextlib.redirect_stdout(f):
                if hasattr(risk_position, 'main'):
                    try:
                        risk_position.main([symbol, str(balance), str(risk_pct)])
                    except TypeError:
                        risk_position.main()

            output = f.getvalue()
            try:
                return json.loads(output)
            except json.JSONDecodeError:
                # Parse text output
                risk = {
                    "balance": balance,
                    "risk_pct": risk_pct,
                    "max_loss": balance * (risk_pct / 100),
                    "position_size": 0.0
                }
                for line in output.split('\n'):
                    if 'position' in line.lower() or 'size' in line.lower():
                        parts = line.split(':', 1)
                        if len(parts) == 2:
                            value_str = parts[1].strip()
                            # Try to extract numeric value
                            for word in value_str.split():
                                if word.replace('.', '').replace('-', '').isdigit():
                                    risk["position_size"] = float(word)
                                    break
                return risk
        else:
            return None
    except Exception as e:
        print(f"Error loading risk_position: {e}", file=sys.stderr)
        return None


def get_forecast_reality_analyzer(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Get forecast reality analyzer data"""
    try:
        script_path = Path(__file__).parent / "forecast_reality_analyzer.py"
        if script_path.exists():
            forecast_analyzer = load_module_from_file(script_path, "forecast_reality_analyzer")
            import io
            import contextlib

            f = io.StringIO()
            with contextlib.redirect_stdout(f):
                if hasattr(forecast_analyzer, 'main'):
                    try:
                        forecast_analyzer.main([symbol, period])
                    except TypeError:
                        forecast_analyzer.main()

            output = f.getvalue()
            try:
                return json.loads(output)
            except json.JSONDecodeError:
                # Parse text output
                forecast = {"consensus": "neutral"}
                for line in output.split('\n'):
                    if 'bull' in line.lower():
                        forecast["consensus"] = "bullish"
                    elif 'bear' in line.lower():
                        forecast["consensus"] = "bearish"
                    elif 'neutral' in line.lower():
                        forecast["consensus"] = "neutral"
                return forecast
        else:
            return None
    except Exception as e:
        print(f"Error loading forecast_reality_analyzer: {e}", file=sys.stderr)
        return None


def calculate_bias_score(market_ctx: Dict, signals: Dict, patterns: Dict, 
                         forecast: Dict) -> Tuple[str, int, float]:
    """Calculate bias score based on multiple factors"""
    score = 0
    reasons = []

    # Market context factors
    if market_ctx:
        # Look for trend indicators like moving averages
        for key, value in market_ctx.items():
            if isinstance(value, str):
                if 'bull' in value.lower() or 'above' in value.lower():
                    score += 15
                    reasons.append("Bullish market context")
                elif 'bear' in value.lower() or 'below' in value.lower():
                    score -= 15
                    reasons.append("Bearish market context")
            elif isinstance(value, (int, float)):
                # Numeric values might represent RSI, MACD, etc.
                if 'rsi' in key.lower():
                    if 30 <= value <= 70:
                        score += 10
                        reasons.append(f"RSI neutral-bullish ({value})")
                    elif value > 70:
                        score -= 10
                        reasons.append(f"RSI overbought ({value})")
                    elif value < 30:
                        score -= 10
                        reasons.append(f"RSI oversold ({value})")

    # Signal factors
    if signals and 'signals' in signals:
        for signal in signals['signals']:
            if 'bull' in signal.lower():
                score += 15
                reasons.append("Bullish signal detected")
            elif 'bear' in signal.lower():
                score -= 15
                reasons.append("Bearish signal detected")

    # Pattern factors
    if patterns and 'patterns' in patterns:
        for pattern in patterns['patterns']:
            if 'bull' in pattern.lower():
                score += 10
                reasons.append("Bullish pattern detected")
            elif 'bear' in pattern.lower():
                score -= 10
                reasons.append("Bearish pattern detected")

    # Forecast factors
    if forecast and 'consensus' in forecast:
        if forecast['consensus'] == 'bullish':
            score += 10
            reasons.append("Forecast consensus bullish")
        elif forecast['consensus'] == 'bearish':
            score -= 10
            reasons.append("Forecast consensus bearish")

    # Determine bias based on score
    if score >= 65:
        bias = "bullish"
    elif 45 <= score <= 64:
        bias = "moderately_bullish"
    elif 35 <= score <= 44:
        bias = "neutral"
    elif 20 <= score <= 34:
        bias = "moderately_bearish"
    else:
        bias = "bearish"

    # Calculate confidence (higher score = higher confidence, but capped)
    confidence = min(95, max(20, 30 + score))

    return bias, score, confidence


def calculate_entry_stop_take_profit(symbol: str, period: str, bias: str, 
                                   market_ctx: Dict) -> Dict:
    """Calculate entry, stop loss, and take profit levels"""
    # Placeholder calculations - in a real implementation, this would use
    # technical analysis to determine actual levels

    # Get current price from market context if available
    current_price = 62000.0  # Default fallback

    if market_ctx:
        # Look for current price in various possible keys
        for key in ['price', 'close', 'current_price', 'latest_close']:
            if key in market_ctx and isinstance(market_ctx[key], (int, float)):
                current_price = market_ctx[key]
                break

    # Calculate levels based on bias
    if bias in ["bullish", "moderately_bullish"]:
        side = "long"
        # Entry zone: current price ± 0.2%
        entry_low = current_price * 0.998
        entry_high = current_price * 1.002

        # Stop: slightly below current (ATR-based in real impl)
        stop_loss = current_price * 0.985  # 1.5% stop for example

        # Take profits: 1.5R and 2.5R targets
        tp_distance = (current_price - stop_loss) * 1.5
        tp1 = current_price + tp_distance
        tp2 = current_price + (tp_distance * 2.5 / 1.5)

    else:
        side = "short"
        # Entry zone: current price ± 0.2%
        entry_low = current_price * 0.998
        entry_high = current_price * 1.002

        # Stop: slightly above current (ATR-based in real impl)
        stop_loss = current_price * 1.015  # 1.5% stop for example

        # Take profits: 1.5R and 2.5R targets
        tp_distance = (stop_loss - current_price) * 1.5
        tp1 = current_price - tp_distance
        tp2 = current_price - (tp_distance * 2.5 / 1.5)

    return {
        "side": side,
        "entry_zone": [round(entry_low, 2), round(entry_high, 2)],
        "stop_loss": round(stop_loss, 2),
        "take_profit": [round(tp1, 2), round(tp2, 2)]
    }


def calculate_risk_metrics(balance: float, risk_pct: float, stop_distance: float, 
                         current_price: float) -> Dict:
    """Calculate risk metrics"""
    max_loss = balance * (risk_pct / 100)
    position_size = abs(max_loss / (current_price - stop_distance)) if current_price != stop_distance else 0

    # Calculate risk/reward ratios
    # Using simplified calculation - in reality would need to consider actual distances
    risk_amount = abs(current_price - stop_distance)
    avg_target = (current_price + stop_distance) / 2  # Placeholder

    if risk_amount > 0:
        rr_tp1 = abs(avg_target - current_price) / risk_amount if avg_target != current_price else 0
        rr_tp2 = abs(avg_target - current_price) / risk_amount if avg_target != current_price else 0
    else:
        rr_tp1 = rr_tp2 = 0

    return {
        "balance": balance,
        "risk_pct": risk_pct,
        "max_loss": max_loss,
        "position_size": round(position_size, 6),
        "risk_reward_tp1": round(rr_tp1, 2),
        "risk_reward_tp2": round(rr_tp2, 2)
    }


def generate_warnings(market_ctx: Dict) -> List[str]:
    """Generate warnings based on market conditions"""
    warnings = []

    if market_ctx:
        # Check for high volatility
        for key, value in market_ctx.items():
            if 'vol' in key.lower() and isinstance(value, (int, float)) and value > 50:
                warnings.append("High volatility detected")
                break

        # Check for extreme RSI
        for key, value in market_ctx.items():
            if 'rsi' in key.lower() and isinstance(value, (int, float)):
                if value > 80:
                    warnings.append("RSI indicates overbought condition")
                elif value < 20:
                    warnings.append("RSI indicates oversold condition")
                break

    return warnings


def generate_invalidations(bias: str, market_ctx: Dict) -> List[str]:
    """Generate invalidation conditions"""
    invalidations = []

    if bias in ["bullish", "moderately_bullish"]:
        invalidations.extend([
            "Close below key support level",
            "Break below recent swing low"
        ])
    else:
        invalidations.extend([
            "Close above key resistance level", 
            "Break above recent swing high"
        ])

    # Add more specific invalidations based on market context
    if market_ctx:
        # Look for moving average levels to add as invalidations
        for key in market_ctx.keys():
            if 'ma' in key.lower() or 'sma' in key.lower() or 'ema' in key.lower():
                if bias in ["bullish", "moderately_bullish"]:
                    invalidations.append(f"Close below {key.upper()}")
                else:
                    invalidations.append(f"Close above {key.upper()}")
                break

    return invalidations


def generate_trade_plan(symbol: str, period: str, lookback_days: int, 
                      balance: float, risk_pct: float, format_type: str) -> Dict:
    """Main function to generate trade plan"""

    # Collect data from all available sources
    sources_used = []
    missing_sources = []

    market_context = get_market_context(symbol, period, lookback_days)
    if market_context:
        sources_used.append("market_context")
    else:
        missing_sources.append("market_context")

    signal_data = get_signal_explainer(symbol, period, lookback_days)
    if signal_data:
        sources_used.append("signal_explainer")
    else:
        missing_sources.append("signal_explainer")

    pattern_data = get_pattern_lab(symbol, period, lookback_days)
    if pattern_data:
        sources_used.append("pattern_lab")
    else:
        missing_sources.append("pattern_lab")

    risk_data = get_risk_position(symbol, period, balance, risk_pct)
    if risk_data:
        sources_used.append("risk_position")
    else:
        missing_sources.append("risk_position")

    forecast_data = get_forecast_reality_analyzer(symbol, period, lookback_days)
    if forecast_data:
        sources_used.append("forecast_reality_analyzer")
    else:
        missing_sources.append("forecast_reality_analyzer")

    # Check if we have sufficient data
    if not any([market_context, signal_data, pattern_data, risk_data, forecast_data]):
        return {
            "status": "insufficient_data",
            "reason": "No data sources available"
        }

    # Calculate bias
    bias, score, confidence = calculate_bias_score(
        market_context, signal_data, pattern_data, forecast_data
    )

    # Calculate entry/stop/take-profit
    trade_levels = calculate_entry_stop_take_profit(
        symbol, period, bias, market_context
    )

    # Calculate risk metrics
    current_price = 62000.0  # Default, would come from market context in real impl
    if market_context:
        for key in ['price', 'close', 'current_price', 'latest_close']:
            if key in market_context and isinstance(market_context[key], (int, float)):
                current_price = market_context[key]
                break

    risk_metrics = calculate_risk_metrics(
        balance, risk_pct, trade_levels["stop_loss"], current_price
    )

    # Generate reasons, warnings, and invalidations
    reasons = [f"SMA20 above SMA50", f"MACD bullish"]  # Placeholder reasons
    warnings = generate_warnings(market_context)
    invalidations = generate_invalidations(bias, market_context)

    # Construct the trade plan
    trade_plan = {
        "status": "ok",
        "symbol": symbol,
        "period": period,
        "bias": bias,
        "score": score,
        "confidence": int(confidence),
        "side": trade_levels["side"],
        "entry_zone": trade_levels["entry_zone"],
        "stop_loss": trade_levels["stop_loss"],
        "take_profit": trade_levels["take_profit"],
        "risk": risk_metrics,
        "reasons": reasons,
        "warnings": warnings,
        "invalidations": invalidations,
        "sources_used": sources_used,
        "missing_sources": missing_sources
    }

    # Format output based on requested format
    if format_type == "json":
        return trade_plan
    elif format_type == "markdown":
        return format_as_markdown(trade_plan)
    elif format_type == "telegram":
        return format_as_telegram(trade_plan)
    else:
        return trade_plan


def format_as_markdown(plan: Dict) -> str:
    """Format trade plan as markdown"""
    if plan.get("status") == "insufficient_data":
        return f"# Trade Plan: {plan.get('symbol', 'N/A')} {plan.get('period', 'N/A')}\n\n{plan.get('reason', 'Insufficient data')}"

    md = f"""# Trade Plan: {plan['symbol']} {plan['period']}

Bias: {plan['bias'].replace('_', ' ').title()}
Confidence: {plan['confidence']}/100

## Setup
Entry zone: {plan['entry_zone'][0]}–{plan['entry_zone'][1]}
Stop loss: {plan['stop_loss']}
Take profit 1: {plan['take_profit'][0]}
Take profit 2: {plan['take_profit'][1]}

## Risk
Balance: {plan['risk']['balance']} USDT
Risk: {plan['risk']['risk_pct']}%
Max loss: {plan['risk']['max_loss']} USDT
Position size: {plan['risk']['position_size']} {plan['symbol'].split('USDT')[0]}
Risk/reward: 1:{plan['risk']['risk_reward_tp1']}

## Reasons
"""
    for reason in plan['reasons']:
        md += f"- {reason}\n"

    md += "\n## Invalidations\n"
    for inv in plan['invalidations']:
        md += f"- {inv}\n"

    if plan['warnings']:
        md += "\n## Warnings\n"
        for warning in plan['warnings']:
            md += f"- {warning}\n"

    return md


def format_as_telegram(plan: Dict) -> str:
    """Format trade plan as compact telegram message"""
    if plan.get("status") == "insufficient_data":
        return f"⚠️ {plan.get('reason', 'Insufficient data')}"

    tg = f"""🎯 {plan['symbol']} {plan['period']} TRADE PLAN

📈 {plan['bias'].replace('_', ' ').upper()}
📊 Conf: {plan['confidence']}/100

🔹 Entry: {plan['entry_zone'][0]}-{plan['entry_zone'][1]}
🔴 Stop: {plan['stop_loss']}
✅ TP: {plan['take_profit'][0]} / {plan['take_profit'][1]}

💰 Risk: {plan['risk']['risk_pct']}% ({plan['risk']['max_loss']} USDT)
⚖️ Size: {plan['risk']['position_size']} {plan['symbol'].split('USDT')[0]}
⚖️ R/R: 1:{plan['risk']['risk_reward_tp1']}"""

    return tg


def main():
    parser = argparse.ArgumentParser(description='Generate advisory trade plan')
    parser.add_argument('--symbol', type=str, required=True, help='Trading symbol (e.g. BTCUSDT)')
    parser.add_argument('--period', type=str, required=True, help='Timeframe (e.g. 60min)')
    parser.add_argument('--lookback-days', type=int, default=14, help='Lookback days for analysis')
    parser.add_argument('--balance', type=float, default=1000, help='Account balance')
    parser.add_argument('--risk-pct', type=float, default=1, help='Risk percentage')
    parser.add_argument('--format', type=str, default='json', choices=['json', 'markdown', 'telegram'], 
                       help='Output format')

    args = parser.parse_args()

    plan = generate_trade_plan(
        args.symbol, 
        args.period, 
        args.lookback_days, 
        args.balance, 
        args.risk_pct, 
        args.format
    )

    if args.format == 'json':
        print(json.dumps(plan, indent=2))
    else:
        print(plan)


if __name__ == "__main__":
    main()"}

