"""
Trade Plan Generator
Generates advisory trading plans based on multiple data sources.

Usage:
    python trade_plan_generator.py --symbol BTCUSDT --period 60min --balance 1000 --risk-pct 1 --format json
"""

import argparse
import json
import sys
from typing import Dict, List, Optional, Tuple, Any
from datetime import datetime


def load_market_context(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Load market context data."""
    try:
        # Import the module dynamically to avoid dependency issues
        import subprocess
        result = subprocess.run([
            sys.executable, "scripts/market_context.py",
            "--symbol", symbol,
            "--period", period,
            "--days", str(lookback_days)
        ], capture_output=True, text=True, timeout=30)

        if result.returncode == 0:
            # Try to parse JSON output
            lines = result.stdout.strip().split('\n')
            for line in reversed(lines):
                line = line.strip()
                if line.startswith('{') and line.endswith('}'):
                    try:
                        return json.loads(line)
                    except json.JSONDecodeError:
                        continue
        return None
    except Exception:
        return None


def load_signal_explainer(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Load signal explainer data."""
    try:
        import subprocess
        result = subprocess.run([
            sys.executable, "scripts/signal_explainer.py",
            "--symbol", symbol,
            "--period", period,
            "--days", str(lookback_days)
        ], capture_output=True, text=True, timeout=30)

        if result.returncode == 0:
            lines = result.stdout.strip().split('\n')
            for line in reversed(lines):
                line = line.strip()
                if line.startswith('{') and line.endswith('}'):
                    try:
                        return json.loads(line)
                    except json.JSONDecodeError:
                        continue
        return None
    except Exception:
        return None


def load_pattern_lab(symbol: str, period: str, lookback_days: int) -> Optional[Dict]:
    """Load pattern lab data."""
    try:
        import subprocess
        result = subprocess.run([
            sys.executable, "scripts/pattern_lab.py",
            "--symbol", symbol,
            "--period", period,
            "--days", str(lookback_days)
        ], capture_output=True, text=True, timeout=30)

        if result.returncode == 0:
            lines = result.stdout.strip().split('\n')
            for line in reversed(lines):
                line = line.strip()
                if line.startswith('{') and line.endswith('}'):
