                if evaluator.update_plan_evaluation(plan["id"], evaluation):
                    print(f"Evaluation completed for plan {plan['id']}: {evaluation['outcome']}")
                else:
                    print(f"Failed to update evaluation for plan {plan['id']}")

    elif args.command == "scorecard":
