def probe_nvidia_key_model(key: str, model: str) -> Dict[str, Any]:
    """
    Test a specific NVIDIA key against its assigned model only (model-bound principle)
    """
    try:
        masked_key = key[:10] + "***"

        base_url = "https://integrate.api.nvidia.com/v1"
        headers = {
            'Authorization': f'Bearer {key}',
            'Content-Type': 'application/json'
        }

        payload = {
            'model': model,
            'messages': [
                {'role': 'system', 'content': 'Return exactly OK.'},
                {'role': 'user', 'content': 'healthcheck'}
            ],
            'max_tokens': 8,
            'temperature': 0
        }

        start_time = time.time()
        req = urllib.request.Request(
            f"{base_url}/chat/completions",
            data=json.dumps(payload).encode('utf-8'),
            headers=headers
        )

        response = urllib.request.urlopen(req, timeout=45)
        response_time = time.time() - start_time

        data = json.loads(response.read().decode('utf-8'))

        # Check if response is valid
        if 'choices' in data and len(data['choices']) > 0:
            content = data['choices'][0].get('message', {}).get('content', '')
            if 'OK' in content or content.lower().strip() == 'ok':
                return {
                    "status": "working",
                    "latency_ms": int(response_time * 1000),
                    "error_class": None
                }
            else:
                return {
                    "status": "failed",
                    "latency_ms": int(response_time * 1000),
                    "error_class": "bad_response_format"
                }
        else:
            return {
                "status": "failed",
                "latency_ms": int(response_time * 1000),
                "error_class": "bad_response_format"
            }

    except urllib.error.HTTPError as e:
        error_msg = e.read().decode('utf-8')
        status_code = e.code

        if status_code == 401:
            return {
                "status": "failed",
                "latency_ms": None,
                "error_class": "auth_header_missing_or_env_not_loaded"
            }
        elif status_code == 403:
            return {
                "status": "failed",
                "latency_ms": None,
                "error_class": "forbidden_model_or_permission"
            }
        elif status_code == 404:
            return {
                "status": "failed",
                "latency_ms": None,
                "error_class": "model_not_found"
            }
        elif status_code == 429:
            return {
                "status": "failed",
                "latency_ms": None,
                "error_class": "quota_or_rate_limit"
            }
        else:
            return {
                "status": "failed",
                "latency_ms": None,
                "error_class": f"provider_error_{status_code}"
            }

    except urllib.error.URLError as e:
        return {
            "status": "failed",
            "latency_ms": None,
            "error_class": "provider_error"
        }

    except Exception as e:
        return {
            "status": "failed",
            "latency_ms": None,
            "error_class": "timeout"
        }


