def test_nvidia_model_bound_keys(config_path: str) -> List[Dict[str, Any]]:
    """
    Test all NVIDIA model-bound keys against their assigned models only
    """
    secrets_path = Path(config_path)
    if not secrets_path.exists():
        return []

    # Load the configuration
    with open(secrets_path, 'r') as f:
        config = yaml.safe_load(f)

    nvidia_configs = config.get('nvidia_model_bound', [])
    results = []

    for nvidia_config in nvidia_configs:
        key = nvidia_config.get('key')
        model = nvidia_config.get('model')
        role = nvidia_config.get('role')
        id_val = nvidia_config.get('id')

        if not key or not model:
            continue  # Skip if missing key or model

        # Test this specific key against its assigned model only (model-bound principle)
        result = probe_nvidia_key_model(key, model)

        entry_result = {
            "id": id_val,
            "model": model,
            "role": role,
            "masked_key": key[:10] + "***",
            "status": result["status"],
            "latency_ms": result["latency_ms"],
            "error_class": result["error_class"]
        }

        results.append(entry_result)

    return results


def test_china_provider_models(config_path: str) -> List[Dict[str, Any]]:
    """
    Test all Chinese multi-model providers
    """
    secrets_path = Path(config_path)
    if not secrets_path.exists():
        return []

    # Load the configuration
    with open(secrets_path, 'r') as f:
        config = yaml.safe_load(f)

    china_providers = config.get('china_multi_model_providers', [])
    results = []

    for provider_config in china_providers:
        provider_id = provider_config.get('id')
        provider_name = provider_config.get('provider')
        base_url = provider_config.get('base_url')
        models = provider_config.get('models', [])
        role = provider_config.get('role')
        key_env = provider_config.get('key_env')

        # Get the API key from environment variable
        api_key = None
        if key_env:
            # Split by '_OR_' and try each environment variable
            env_options = key_env.split('_OR_')
            for env_opt in env_options:
                api_key = os.environ.get(env_opt.strip())
                if api_key:
                    break

        if not api_key:
            # If no API key found, create a result showing no key
            results.append({
                "id": provider_id,
                "provider": provider_name,
                "role": role,
                "models_tested": models,
                "working_models": [],
                "errors": [{"model": model, "error_class": "no_key_available"} for model in models]
            })
            continue

        # Test each model with this provider key
        working_models = []
        errors = []

        for model in models:
            result = probe_china_provider_model(base_url, api_key, model)
            if result["status"] == "working":
                working_models.append({
                    "model": result["model"],
                    "latency_ms": result["latency_ms"]
                })
            else:
                errors.append({
                    "model": result["model"],
                    "error_class": result["error_class"]
                })

        results.append({
            "id": provider_id,
            "provider": provider_name,
            "role": role,
            "models_tested": models,
            "working_models": working_models,
            "errors": errors
        })

    return results


def test_deepseek_official(config_path: str) -> List[Dict[str, Any]]:
    """
    Test DeepSeek official API keys
    """
    secrets_path = Path(config_path)
    if not secrets_path.exists():
        return []

    # Load the configuration
    with open(secrets_path, 'r') as f:
        config = yaml.safe_load(f)

    deepseek_configs = config.get('deepseek_official', [])
    results = []

    for ds_config in deepseek_configs:
        id_val = ds_config.get('id')
        models = ds_config.get('models', [])
        role = ds_config.get('role')
        key = ds_config.get('key')

        if not key:
            continue  # Skip if no key

        # Test each model with this DeepSeek key
        working_models = []
        errors = []

        for model in models:
            try:
                masked_key = key[:5] + "***"

                headers = {
                    'Authorization': f'Bearer {key}',
                    'Content-Type': 'application/json'
                }

                payload = {
                    'model': model,
                    'messages': [
                        {'role': 'system', 'content': 'Return exactly OK.'},
                        {'role': 'user', 'content': 'healthcheck'}
                    ],
                    'max_tokens': 8,
                    'temperature': 0
                }

                start_time = time.time()
                req = urllib.request.Request(
                    "https://api.deepseek.com/chat/completions",
                    data=json.dumps(payload).encode('utf-8'),
                    headers=headers
                )

                response = urllib.request.urlopen(req, timeout=45)
                response_time = time.time() - start_time

                data = json.loads(response.read().decode('utf-8'))

                # Check if response is valid
                if 'choices' in data and len(data['choices']) > 0:
                    content = data['choices'][0].get('message', {}).get('content', '')
                    if 'OK' in content or content.lower().strip() == 'ok':
                        working_models.append({
                            "model": model,
                            "latency_ms": int(response_time * 1000)
                        })
                    else:
                        errors.append({
                            "model": model,
                            "error_class": "bad_response_format"
                        })
                else:
                    errors.append({
                        "model": model,
                        "error_class": "bad_response_format"
                    })

            except urllib.error.HTTPError as e:
                status_code = e.code
                error_class = None
                if status_code == 401:
                    error_class = "auth_header_missing_or_env_not_loaded"
                elif status_code == 403:
                    error_class = "forbidden_model_or_permission"
                elif status_code == 404:
                    error_class = "model_not_found"
                elif status_code == 429:
                    error_class = "quota_or_rate_limit"
                elif status_code == 402:
                    error_class = "billing_or_quota"
                else:
                    error_class = f"provider_error_{status_code}"

                errors.append({
                    "model": model,
                    "error_class": error_class
                })

            except Exception as e:
                errors.append({
                    "model": model,
                    "error_class": "timeout"
                })

        results.append({
            "id": id_val,
            "provider": "deepseek_official",
            "role": role,
            "models_tested": models,
            "working_models": working_models,
            "errors": errors
        })

    return results


def main():
