        for entry in provider.get("entries", [])
    )

    has_working_china = any(
        provider["provider"] != "nvidia" and provider["working_models"]
        for provider in results["providers"]
    )

    if has_working_nvidia or has_working_china:
        results["status"] = "ok"
    elif nvidia_results or china_results:
        results["status"] = "partial"
    else:
        results["status"] = "no_keys"

    # Determine recommended routing based on working models
    for provider in results["providers"]:
        if provider["provider"] == "nvidia":
            for entry in provider.get("entries", []):
                if entry["status"] == "working":
                    role = entry["role"]
                    model = entry["model"]

                    if role == "main_coding_driver":
                        results["recommended_routing"]["main_coding_driver"] = f"NVIDIA:{model}"
                    elif role == "heavy_reviewer":
                        results["recommended_routing"]["heavy_reviewer"] = f"NVIDIA:{model}"
