                        results["recommended_routing"]["bug_hunt"] = f"NVIDIA:{model}"
                    elif role == "long_context_docs":
                        results["recommended_routing"]["long_context_docs"] = f"NVIDIA:{model}"
                    elif role == "russian_reports":
                        results["recommended_routing"]["russian_reports"] = f"NVIDIA:{model}"

        elif "qwen" in provider["provider"]:
