## Status: {results['status'].upper()}

### NVIDIA Model-Bound Keys
"""
        for provider in results["providers"]:
            if provider["provider"] == "nvidia":
                for entry in provider.get("entries", []):
                    status_icon = "✅" if entry["status"] == "working" else "❌"
