        md += "\n### Chinese Multi-Model Providers\n"
        for provider in results["providers"]:
            if provider["provider"] != "nvidia":
                md += f"- {provider['provider']}: {len(provider['working_models'])}/{len(provider['models_tested'])} models working\n"

        md += "\n### Recommended Routing\n"
        for role, model in results["recommended_routing"].items():
